table.create-sql:
CREATE TABLE IF NOT EXISTS `wp_vogo_category_malls` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `category_id` bigint(20) unsigned NOT NULL COMMENT 'Links to wp_terms.term_id / product_cat', `mall_id` bigint(20) unsigned NOT NULL COMMENT 'Links to wp_mall_locations.id', `created_at` datetime DEFAULT current_timestamp(), `created_by` bigint(20) DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) DEFAULT NULL, PRIMARY KEY (`id`), UNIQUE KEY `uniq_category_mall` (`category_id`,`mall_id`), KEY `idx_category` (`category_id`), KEY `idx_mall` (`mall_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_chat_blocklist` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `blocker_id` bigint(20) unsigned NOT NULL, `blocked_id` bigint(20) unsigned NOT NULL, `blocked_at` datetime NOT NULL DEFAULT current_timestamp(), PRIMARY KEY (`id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_chat_history` (
`id` mediumint(9) NOT NULL AUTO_INCREMENT, `user_id` varchar(100) NOT NULL, `message_type` enum('user','ai') NOT NULL, `message` text NOT NULL, `timestamp` datetime DEFAULT current_timestamp(), PRIMARY KEY (`id`), KEY `user_id` (`user_id`), KEY `timestamp` (`timestamp`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_chat_message` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `thread_id` bigint(20) unsigned NOT NULL, `sender_id` bigint(20) unsigned NOT NULL, `message_text` text DEFAULT NULL, `message_type` varchar(20) DEFAULT 'text', `attachment_url` text DEFAULT NULL, `sent_at` datetime NOT NULL DEFAULT current_timestamp(), `is_read` tinyint(1) DEFAULT 0, PRIMARY KEY (`id`), KEY `thread_id` (`thread_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_chat_thread` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `user_from` bigint(20) unsigned NOT NULL, `user_to` bigint(20) unsigned NOT NULL, `created_at` datetime NOT NULL DEFAULT current_timestamp(), `last_updated_at` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(), `is_muted` tinyint(1) DEFAULT 0, `status` varchar(20) DEFAULT 'active', PRIMARY KEY (`id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_cities` (
`id` bigint(20) UNSIGNED NOT NULL, `city_name` varchar(100) NOT NULL, `latitude` decimal(10,7) DEFAULT NULL, `longitude` decimal(10,7) DEFAULT NULL, `status` tinyint(1) DEFAULT 1, `created_at` timestamp NULL DEFAULT current_timestamp(), `modified_by` bigint(20) UNSIGNED DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `position` float DEFAULT 0, PRIMARY KEY (`id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_mall_locations` (
`id` bigint(20) UNSIGNED NOT NULL, `mall_name` varchar(255) NOT NULL, `city` varchar(255) NOT NULL, `location_code` varchar(50) NOT NULL, `status` enum('active','inactive') NOT NULL DEFAULT 'active', `street_address` varchar(255) NOT NULL, `position` float DEFAULT 0, PRIMARY KEY (`id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_order_transporter_pos` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `order_id` bigint(20) unsigned NOT NULL, `client_id` bigint(20) unsigned NOT NULL, `transporter_id` bigint(20) unsigned NOT NULL, `provider_id` bigint(20) unsigned NOT NULL, `latitude` decimal(10,7) NOT NULL, `longitude` decimal(10,7) NOT NULL, `status` varchar(32) NOT NULL, `created_at` datetime NOT NULL DEFAULT current_timestamp(), `created_by` bigint(20) unsigned NOT NULL, PRIMARY KEY (`id`), KEY `k_order` (`order_id`), KEY `k_transporter` (`transporter_id`), KEY `k_order_time` (`order_id`,`created_at`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_order_transporter_rejects` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `order_id` bigint(20) unsigned NOT NULL, `transporter_id` bigint(20) unsigned NOT NULL, `reason` text DEFAULT NULL, `created_at` datetime NOT NULL DEFAULT current_timestamp(), `created_by` bigint(20) unsigned NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `uq_order_transporter` (`order_id`,`transporter_id`), KEY `k_order` (`order_id`), KEY `k_transporter` (`transporter_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_order_vendor` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `order_id` bigint(20) unsigned NOT NULL COMMENT 'FK -> wp_posts.ID (shop_order)', `child_order_id` bigint(20) unsigned DEFAULT NULL, `vendor_id` int(11) NOT NULL COMMENT 'FK -> wp_provider_feeds.id', `items_count` int(11) NOT NULL DEFAULT 0, `items_subtotal` decimal(18,2) NOT NULL DEFAULT 0.00, `items_total` decimal(18,2) NOT NULL DEFAULT 0.00, `tax_total` decimal(18,2) NOT NULL DEFAULT 0.00, `shipping_total` decimal(18,2) NOT NULL DEFAULT 0.00, `status` enum('active','hidden') NOT NULL DEFAULT 'active', `created_at` datetime DEFAULT current_timestamp(), `created_by` bigint(20) unsigned DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) unsigned DEFAULT NULL, PRIMARY KEY (`id`), UNIQUE KEY `uniq_order_vendor` (`order_id`,`vendor_id`), KEY `idx_vendor` (`vendor_id`), KEY `idx_order` (`order_id`), KEY `idx_child` (`child_order_id`), CONSTRAINT `fk_ov_order` FOREIGN KEY (`order_id`) REFERENCES `wp_posts` (`ID`) ON DELETE CASCADE ON UPDATE CASCADE
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_orders` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `parent_order_id` bigint(20) unsigned NOT NULL DEFAULT 0, `client_id` bigint(20) unsigned NOT NULL, `provider_id` bigint(20) unsigned NOT NULL, `picking_point_id` bigint(20) unsigned DEFAULT NULL, `pick_latitude` decimal(10,7) DEFAULT NULL, `pick_longitude` decimal(10,7) DEFAULT NULL, `notes_customer` text DEFAULT NULL, `notes_provider` text DEFAULT NULL, `notes_transporter` text DEFAULT NULL, `city_id` bigint(20) unsigned NOT NULL, `total_amount` decimal(12,2) NOT NULL DEFAULT 0.00, `currency` char(3) NOT NULL DEFAULT 'RON', `payment_method_title` varchar(255) DEFAULT NULL, `status` varchar(32) NOT NULL, `delivery_type` enum('DIRECT','POSTAL','COURIER','ELECTRONIC','TAXI') NOT NULL DEFAULT 'DIRECT', `created_at` datetime NOT NULL, `end_lat` decimal(10,7) DEFAULT NULL, `end_long` decimal(10,7) DEFAULT NULL, `address_pick` varchar(512) DEFAULT NULL, `address_end` varchar(512) DEFAULT NULL, `distance_km` decimal(10,3) DEFAULT NULL, `calculated_fields` tinyint(1) NOT NULL DEFAULT 0, `created_by` bigint(20) DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) DEFAULT NULL, `order_short_description` text DEFAULT NULL COMMENT 'Short description of the order', `relevant_image` varchar(512) DEFAULT NULL COMMENT 'Representative image URL/path', `provider_name` varchar(255) DEFAULT NULL, PRIMARY KEY (`id`), KEY `k_city_status` (`city_id`,`status`), KEY `k_provider` (`provider_id`), KEY `k_picking_point` (`picking_point_id`), KEY `idx_provider_mod` (`provider_id`,`modified_at`), KEY `idx_provider_created` (`provider_id`,`created_at`), KEY `idx_client_created` (`client_id`,`created_at`), KEY `idx_parent_order_id` (`parent_order_id`), KEY `idx_vendor_id` (`provider_id`), KEY `idx_currency` (`currency`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_orders_delivery` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `order_id` bigint(20) unsigned NOT NULL, `current_status` varchar(32) NOT NULL DEFAULT 'NEW', `cancel_reason` varchar(512) DEFAULT NULL, `accepted_date` datetime DEFAULT NULL, `transporter_id` bigint(20) unsigned DEFAULT NULL, `transport_end_date` datetime DEFAULT NULL, `last_lat` decimal(10,7) DEFAULT NULL, `last_lng` decimal(10,7) DEFAULT NULL, `last_update_at` datetime DEFAULT NULL, `notes` varchar(255) DEFAULT NULL, `created_at` datetime NOT NULL DEFAULT current_timestamp(), `created_by` bigint(20) unsigned NOT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) unsigned DEFAULT NULL, PRIMARY KEY (`id`), UNIQUE KEY `u_order` (`order_id`), KEY `k_transporter` (`transporter_id`), KEY `k_accepted_date` (`accepted_date`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_orders_lines` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `order_id` bigint(20) unsigned NOT NULL, `order_item_id` bigint(20) unsigned NOT NULL DEFAULT 0, `product_name` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL, `product_id` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci DEFAULT NULL, `variation_id` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci DEFAULT NULL, `qty` decimal(12,3) DEFAULT NULL, `line_subtotal` decimal(12,2) DEFAULT NULL, `line_subtotal_tax` decimal(12,2) DEFAULT NULL, `line_total` decimal(12,2) DEFAULT NULL, `line_tax` decimal(12,2) DEFAULT NULL, `tax_rate` decimal(5,2) DEFAULT NULL, `discount_total` decimal(12,2) DEFAULT 0.00, `discount_percent` decimal(5,2) DEFAULT NULL, `created_at` datetime DEFAULT current_timestamp(), `created_by` bigint(20) DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) DEFAULT NULL, `vendor_id` bigint(20) unsigned DEFAULT NULL, `vendor_name` varchar(255) DEFAULT NULL, PRIMARY KEY (`id`), KEY `idx_order_id` (`order_id`), KEY `idx_order_product` (`order_id`,`product_id`(191)), KEY `idx_vendor_id` (`vendor_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_otps` (
  phone VARCHAR(20) NOT NULL,
  otp INT NOT NULL,
  created_at DATETIME NOT NULL,
  PRIMARY KEY (phone)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_product_action` (
`ID` int(10) NOT NULL AUTO_INCREMENT, `ID_PRODUCT` int(10) NOT NULL COMMENT 'FK PRODUCT-ID', `ACTION_TYPE` varchar(100) NOT NULL COMMENT 'WHATSAPP/LINK/AI', `ACTION_LABEL` varchar(500) NOT NULL, `ACTION_DETAILS` varchar(1000) NOT NULL, `ICON_CODE` varchar(500) NOT NULL COMMENT 'font-awsome icon code', `WHATSAPP_NUMBER` text NOT NULL, PRIMARY KEY (`ID`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_product_category_cities` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `category_id` bigint(20) unsigned NOT NULL COMMENT 'Links to wp_terms.term_id / product_cat', `city_id` bigint(20) unsigned NOT NULL COMMENT 'Links to wp_cities.id', `created_at` datetime DEFAULT current_timestamp(), `created_by` bigint(20) DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) DEFAULT NULL, PRIMARY KEY (`id`), UNIQUE KEY `uniq_category_city` (`category_id`,`city_id`), KEY `idx_category` (`category_id`), KEY `idx_city` (`city_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_product_cities` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `product_id` bigint(20) unsigned NOT NULL, `city_id` bigint(20) unsigned NOT NULL, `created_by` bigint(20) unsigned DEFAULT 0, `created_at` datetime DEFAULT current_timestamp(), `modified_by` bigint(20) unsigned DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), PRIMARY KEY (`id`), UNIQUE KEY `unique_product_city` (`product_id`,`city_id`), KEY `idx_product_id` (`product_id`), KEY `idx_city_id` (`city_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_product_malls` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `product_id` bigint(20) unsigned NOT NULL, `mall_id` bigint(20) unsigned NOT NULL, `created_at` datetime DEFAULT current_timestamp(), `created_by` bigint(20) unsigned DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) unsigned DEFAULT NULL, PRIMARY KEY (`id`), UNIQUE KEY `uq_product_mall` (`product_id`,`mall_id`), KEY `idx_product_id` (`product_id`), KEY `idx_mall_id` (`mall_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_product_meta_action` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `product_id` bigint(20) unsigned NOT NULL COMMENT 'FK to wp_posts.ID (WooCommerce product)', `product_main_category_id` bigint(20) unsigned DEFAULT NULL COMMENT 'FK to wp_terms.term_id (main product_cat)', `camera_broadcast_url` varchar(500) DEFAULT NULL, `zoom_live_call_link` varchar(500) DEFAULT NULL, `whatsapp_contact_url` varchar(500) DEFAULT NULL, `suggest_service_link` varchar(500) DEFAULT NULL, `action_whatsapp_label` varchar(255) DEFAULT NULL, `action_whatsapp_number` varchar(50) DEFAULT NULL, `action_whatsapp_message` text DEFAULT NULL, `action_url_label` varchar(255) DEFAULT NULL, `action_url_link` varchar(500) DEFAULT NULL, `created_at` datetime DEFAULT current_timestamp(), `created_by` bigint(20) DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) DEFAULT NULL, PRIMARY KEY (`id`), UNIQUE KEY `uniq_product` (`product_id`), KEY `idx_product` (`product_id`), KEY `idx_category` (`product_main_category_id`), KEY `idx_product_main_category` (`product_main_category_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_product_recommendations` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `user_id` bigint(20) unsigned NOT NULL, `product_id` bigint(20) unsigned NOT NULL, `recommended_at` datetime NOT NULL DEFAULT current_timestamp(), PRIMARY KEY (`id`), UNIQUE KEY `user_product_unique` (`user_id`,`product_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_product_tbl` (
`product_id` bigint(20) unsigned NOT NULL, `product_name` varchar(255) NOT NULL, `product_slug` varchar(200) NOT NULL, `short_description` mediumtext DEFAULT NULL, `description` longtext DEFAULT NULL, `status` enum('publish','draft','pending','private','trash') NOT NULL DEFAULT 'draft', `product_type` enum('simple','variable','grouped','external','unknown') NOT NULL DEFAULT 'unknown', `sku` varchar(100) DEFAULT NULL, `regular_price` decimal(19,4) DEFAULT NULL, `sale_price` decimal(19,4) DEFAULT NULL, `price` decimal(19,4) DEFAULT NULL, `max_price` decimal(19,4) DEFAULT NULL, `manage_stock` tinyint(1) NOT NULL DEFAULT 0, `stock_qty` decimal(19,4) DEFAULT NULL, `stock_status` enum('instock','outofstock','onbackorder') NOT NULL DEFAULT 'instock', `categories` text DEFAULT NULL, `tags` text DEFAULT NULL, `thumbnail_id` bigint(20) unsigned DEFAULT NULL, `image_url` varchar(1024) DEFAULT NULL, `published_date` datetime DEFAULT NULL, `position` int(11) DEFAULT NULL, `visibility` varchar(32) DEFAULT 'public', `seo_title` text DEFAULT NULL, `seo_description` longtext DEFAULT NULL, `product_image_id` bigint(20) unsigned DEFAULT NULL, `product_image_url` varchar(1024) DEFAULT NULL, `brand` varchar(100) DEFAULT NULL, `product_providers` varchar(255) DEFAULT NULL, `provider_id` bigint(20) unsigned DEFAULT NULL, `category_id` bigint(20) unsigned DEFAULT NULL, `category_name` varchar(255) DEFAULT NULL, `created_at` datetime NOT NULL DEFAULT current_timestamp(), `created_by` bigint(20) unsigned DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) unsigned DEFAULT NULL, PRIMARY KEY (`product_id`), UNIQUE KEY `uk_vogo_sku` (`sku`), KEY `idx_vogo_slug` (`product_slug`), KEY `idx_vogo_status` (`status`), KEY `idx_vogo_type` (`product_type`), KEY `idx_vogo_stock_status` (`stock_status`), KEY `idx_vogo_price` (`price`), KEY `idx_vogo_position` (`position`), KEY `idx_vogo_provider_id` (`provider_id`), KEY `idx_vogo_category_id` (`category_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_support_users` (
`user_id` bigint(20) UNSIGNED NOT NULL COMMENT 'WP user ID', `nickname` varchar(80) NOT NULL COMMENT 'Short display name', `available` tinyint(1) NOT NULL DEFAULT 0 COMMENT '1=available, 0=unavailable', `created_at` datetime DEFAULT current_timestamp() COMMENT 'Row creation datetime (DB-managed)', `created_by` bigint(20) UNSIGNED DEFAULT NULL COMMENT 'Creator user id (from JWT)', `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp() COMMENT 'Last modification (DB-managed)', `modified_by` bigint(20) UNSIGNED DEFAULT NULL COMMENT 'Last modifier user id (from JWT)'
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_thread_calls` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `channel_name` varchar(128) NOT NULL, `UserId_From` bigint(20) unsigned NOT NULL, `UserId_To` bigint(20) unsigned NOT NULL, `discussion_id` bigint(20) unsigned DEFAULT NULL, `start` datetime NOT NULL DEFAULT current_timestamp(), `end` datetime DEFAULT NULL, `duration_seconds` int(10) unsigned DEFAULT NULL, `type` enum('VOICE','VIDEO') NOT NULL, `is_video` tinyint(1) NOT NULL DEFAULT 0, `is_voice` tinyint(1) NOT NULL DEFAULT 0, `ended_by_userid` bigint(20) unsigned DEFAULT NULL, `agora_token` text DEFAULT NULL, `token_expire_at` datetime DEFAULT NULL, `status` enum('RINGING','ONGOING','ENDED','MISSED','DECLINED','FAILED','CANCELLED') NOT NULL DEFAULT 'RINGING', `created_at` datetime NOT NULL DEFAULT current_timestamp(), `created_by` bigint(20) DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) DEFAULT NULL, `caller_agora_token` varchar(512) DEFAULT NULL, `receiver_agora_token` varchar(512) DEFAULT NULL, PRIMARY KEY (`id`), UNIQUE KEY `uk_channel_name` (`channel_name`), KEY `idx_receiver_status` (`UserId_To`,`status`), KEY `idx_caller_created` (`UserId_From`,`created_at`), KEY `idx_discussion` (`discussion_id`), KEY `idx_status` (`status`), KEY `idx_end` (`end`), KEY `idx_thread_calls_channel` (`channel_name`), KEY `idx_thread_calls_status` (`status`), KEY `idx_thread_calls_users` (`UserId_From`,`UserId_To`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_transporters` (
`user_id` bigint(20) unsigned NOT NULL, `first_name` varchar(100) DEFAULT NULL, `second_name` varchar(100) DEFAULT NULL, `nickname` varchar(100) DEFAULT NULL, `plate_number` varchar(32) DEFAULT NULL, `auto_type` varchar(50) DEFAULT NULL, `auto_model` varchar(100) DEFAULT NULL, `auto_year` smallint(5) unsigned DEFAULT NULL, `auto_colour` varchar(50) DEFAULT NULL, `auto_places` tinyint(3) unsigned DEFAULT NULL, `auto_rank` tinyint(3) unsigned DEFAULT NULL, `company_name` varchar(150) DEFAULT NULL, `tax_id` varchar(32) DEFAULT NULL, `phone` varchar(32) DEFAULT NULL, `email` varchar(150) DEFAULT NULL, `city_id` int(10) unsigned DEFAULT NULL, `country_code` char(2) DEFAULT NULL, `service_radius_km` decimal(5,2) DEFAULT NULL, `is_people_licensed` tinyint(1) DEFAULT 0, `is_goods_licensed` tinyint(1) DEFAULT 0, `is_food_licensed` tinyint(1) DEFAULT 0, `vehicle_photo_url` varchar(255) DEFAULT NULL, `driver_photo_url` varchar(255) DEFAULT NULL, `notes` text DEFAULT NULL, `created_at` datetime DEFAULT current_timestamp(), `created_by` bigint(20) unsigned DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) unsigned DEFAULT NULL, PRIMARY KEY (`user_id`), UNIQUE KEY `uniq_plate` (`plate_number`), KEY `idx_nickname` (`nickname`), KEY `idx_auto_type` (`auto_type`), KEY `idx_auto_year` (`auto_year`), KEY `idx_city_id` (`city_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_user_addresses` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `user_id` bigint(20) unsigned NOT NULL, `address_name` varchar(255) NOT NULL, `street_address` text NOT NULL, `street_address_2` text DEFAULT NULL, `city` varchar(255) NOT NULL, `county` varchar(255) NOT NULL, `address_code` varchar(255) NOT NULL, `latitude` decimal(10,6) DEFAULT NULL, `longitude` decimal(10,6) DEFAULT NULL, `status` enum('active','inactive') NOT NULL DEFAULT 'inactive', PRIMARY KEY (`id`), UNIQUE KEY `uniq_user_label` (`user_id`,`address_name`), UNIQUE KEY `uniq_user_label2` (`user_id`,`address_name`), KEY `idx_user_status` (`user_id`,`status`), KEY `idx_user_city` (`user_id`,`city`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_user_bank_accounts` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `user_id` bigint(20) unsigned NOT NULL, `account_holder_name` varchar(150) NOT NULL, `bank_name` varchar(150) NOT NULL, `account_number` varchar(64) NOT NULL, `iban_number` varchar(64) DEFAULT '', `ifsc_code` varchar(64) DEFAULT '', `is_primary` tinyint(1) NOT NULL DEFAULT 0, `status` enum('active','hidden') NOT NULL DEFAULT 'active', `created_at` datetime DEFAULT current_timestamp(), `created_by` bigint(20) DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) DEFAULT NULL, PRIMARY KEY (`id`), KEY `idx_user` (`user_id`), KEY `idx_primary` (`user_id`,`is_primary`), KEY `idx_iban` (`user_id`,`iban_number`), KEY `idx_accnum` (`user_id`,`account_number`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_user_document_data` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `user_id` bigint(20) unsigned NOT NULL, `document_id` bigint(20) unsigned NOT NULL, `document_link` text NOT NULL, `created_at` datetime DEFAULT current_timestamp(), `created_by` bigint(20) unsigned DEFAULT NULL, `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(), `updated_by` bigint(20) unsigned DEFAULT NULL, PRIMARY KEY (`id`), KEY `document_id` (`document_id`), KEY `user_id` (`user_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_user_documents_def` (
`id` bigint(20) UNSIGNED NOT NULL, `document_type` varchar(400) NOT NULL, `required` tinyint(1) NOT NULL DEFAULT 0, `apply_to_role` varchar(400) NOT NULL CHECK (`apply_to_role` in ('vendor','transport','client','admin','vendor2')), `position` float DEFAULT 0, `created_at` datetime DEFAULT current_timestamp(), `created_by` bigint(20) UNSIGNED DEFAULT NULL, `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(), `updated_by` bigint(20) UNSIGNED DEFAULT NULL, PRIMARY KEY (`id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_user_email_otp` (
`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT, `user_id` BIGINT UNSIGNED NOT NULL, `email` VARCHAR(191) NOT NULL, `otp_code` CHAR(6) NOT NULL, -- A-Z0-9 (uppercase) sau 0-9 `expires_at` DATETIME NOT NULL, -- ex. NOW()+INTERVAL 15 MINUTE `verified_at` DATETIME DEFAULT NULL, `attempts` TINYINT UNSIGNED NOT NULL DEFAULT 0, `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (`id`), KEY `idx_user_exp` (`user_id`,`expires_at`), KEY `idx_email` (`email`), KEY `idx_verified` (`verified_at`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_user_group_categories` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `group_id` int(11) NOT NULL, `category_id` bigint(20) unsigned NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `group_category_unique` (`group_id`,`category_id`), KEY `category_id` (`category_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_user_group_users` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `group_id` int(11) NOT NULL, `user_id` bigint(20) unsigned NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `user_group_unique` (`group_id`,`user_id`), KEY `user_id` (`user_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_user_groups` (
`id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT, `user_id` int(11) NOT NULL, `group_id` int(11) NOT NULL, `name` varchar(255) NOT NULL, `created_at` datetime DEFAULT current_timestamp(), `label` varchar(255) DEFAULT NULL, PRIMARY KEY (`id`), KEY `idx_user_id` (`user_id`), KEY `idx_group_id` (`group_id`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_user_pin_code` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `user_id` bigint(20) unsigned NOT NULL, `brand_name` varchar(191) NOT NULL, `pincode` varchar(32) NOT NULL, `otp_code` varchar(32) DEFAULT NULL, `created_at` datetime NOT NULL DEFAULT current_timestamp(), PRIMARY KEY (`id`), KEY `idx_user_brand_pin` (`user_id`,`brand_name`,`pincode`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_vendors_picking_points` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `provider_id` bigint(20) unsigned NOT NULL, `city_id` bigint(20) unsigned NOT NULL, `location_code` varchar(191) NOT NULL, `latitude` decimal(10,7) NOT NULL, `longitude` decimal(10,7) NOT NULL, `is_primary` tinyint(1) NOT NULL DEFAULT 1, `is_active` tinyint(1) NOT NULL DEFAULT 1, `created_at` datetime NOT NULL DEFAULT current_timestamp(), `created_by` bigint(20) unsigned NOT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) unsigned DEFAULT NULL, PRIMARY KEY (`id`), UNIQUE KEY `uq_vendor_city_code` (`provider_id`,`city_id`,`location_code`), KEY `k_provider` (`provider_id`), KEY `k_city` (`city_id`), KEY `k_active_primary` (`is_active`,`is_primary`), KEY `k_provider_city` (`provider_id`,`city_id`,`is_active`,`is_primary`)
) {charset_collate};

CREATE TABLE IF NOT EXISTS `wp_vogo_vogo_category_meta_action` (
`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `category_id` bigint(20) unsigned NOT NULL COMMENT 'FK to wp_terms.term_id (product_cat)', `camera_broadcast_url` varchar(500) DEFAULT NULL, `zoom_live_call_link` varchar(500) DEFAULT NULL, `whatsapp_contact_url` varchar(500) DEFAULT NULL, `suggest_service_link` varchar(500) DEFAULT NULL, `action_whatsapp_label` varchar(255) DEFAULT NULL, `action_whatsapp_number` varchar(50) DEFAULT NULL, `action_whatsapp_message` text DEFAULT NULL, `action_url_label` varchar(255) DEFAULT NULL, `action_url_link` varchar(500) DEFAULT NULL, `created_at` datetime DEFAULT current_timestamp(), `created_by` bigint(20) DEFAULT NULL, `modified_at` datetime DEFAULT NULL ON UPDATE current_timestamp(), `modified_by` bigint(20) DEFAULT NULL, PRIMARY KEY (`id`), UNIQUE KEY `uniq_category` (`category_id`), KEY `idx_category` (`category_id`)
) {charset_collate};

procedure.create-sql:
CREATE PROCEDURE vogo_sync_woo_users_tovogo (IN p_user_id BIGINT) BEGIN DECLARE v_is_single BOOLEAN DEFAULT FALSE; SET v_is_single = (p_user_id IS NOT NULL AND p_user_id > 0);
IF v_is_single THEN INSERT INTO {prefix}vogo_user_info (user_id, created_at) SELECT u.ID, NOW() FROM {prefix}users u WHERE u.ID = p_user_id AND NOT EXISTS (SELECT 1 FROM {prefix}vogo_user_info vui WHERE vui.user_id=u.ID); ELSE INSERT INTO {prefix}vogo_user_info (user_id, created_at) SELECT u.ID, NOW() FROM {prefix}users u WHERE NOT EXISTS (SELECT 1 FROM {prefix}vogo_user_info vui WHERE vui.user_id=u.ID); END IF;
IF v_is_single THEN UPDATE {prefix}vogo_user_info vui JOIN ( SELECT um.user_id, MAX(CASE WHEN um.meta_key='billing_company' THEN um.meta_value END) AS billing_company, MAX(CASE WHEN um.meta_key='phone' THEN um.meta_value END) AS user_phone FROM {prefix}usermeta um WHERE um.user_id = p_user_id AND um.meta_key IN ('billing_company','phone') GROUP BY um.user_id ) m ON m.user_id = vui.user_id SET vui.company_name = COALESCE(NULLIF(m.billing_company,''), vui.company_name), vui.phone = COALESCE(NULLIF(m.user_phone,''), vui.phone), vui.sms = COALESCE(NULLIF(m.user_phone,''), vui.sms); ELSE UPDATE {prefix}vogo_user_info vui JOIN ( SELECT um.user_id, MAX(CASE WHEN um.meta_key='billing_company' THEN um.meta_value END) AS billing_company, MAX(CASE WHEN um.meta_key='phone' THEN um.meta_value END) AS user_phone FROM {prefix}usermeta um WHERE um.meta_key IN ('billing_company','phone') GROUP BY um.user_id ) m ON m.user_id = vui.user_id SET vui.company_name = COALESCE(NULLIF(m.billing_company,''), vui.company_name), vui.phone = COALESCE(NULLIF(m.user_phone,''), vui.phone), vui.sms = COALESCE(NULLIF(m.user_phone,''), vui.sms); END IF; END

trigger.create-sql:
CREATE TRIGGER `{prefix}support_users_AD` AFTER DELETE ON `{prefix}vogo_support_users` FOR EACH ROW
BEGIN
  /* Keep a lightweight trigger body so diagnostics can create the trigger even when audit tables are absent. */
  SET @vogo_support_users_ad = OLD.user_id;
END

CREATE TRIGGER `{prefix}support_users_AU` AFTER UPDATE ON `{prefix}vogo_support_users` FOR EACH ROW
BEGIN
  /* Keep a lightweight trigger body so diagnostics can create the trigger even when audit tables are absent. */
  SET @vogo_support_users_au = NEW.user_id;
END
